@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap');

/* ── Full-page wrapper with blurple gradient ── */
.wrapper {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2rem 1.5rem;
  background: linear-gradient(135deg,
      #2c2078 0%,
      #3a2a9e 25%,
      #5865f2 55%,
      #4752c4 80%,
      #2c2078 100%);
  font-family: 'Outfit', 'Helvetica Neue', Arial, sans-serif;
  position: relative;
  overflow: hidden;
}

/* ── Star field ── */
.starField {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
}

.star {
  position: absolute;
  background: #fff;
  border-radius: 50%;
  opacity: 0;
  animation: twinkle 3s ease-in-out infinite;
}

@keyframes twinkle {

  0%,
  100% {
    opacity: 0;
    transform: scale(0.5);
  }

  50% {
    opacity: 0.7;
    transform: scale(1);
  }
}

/* ── Frosted glass card ── */
.card {
  width: 100%;
  max-width: 440px;
  background: rgba(30, 31, 34, 0.85);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  padding: 2.5rem 2.5rem 2rem;
  box-shadow:
    0 20px 60px rgba(0, 0, 0, 0.4),
    0 0 0 1px rgba(255, 255, 255, 0.04) inset;
  position: relative;
  z-index: 1;
  animation: cardIn 0.5s ease forwards;
}

@keyframes cardIn {
  from {
    opacity: 0;
    transform: translateY(20px) scale(0.97);
  }

  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

/* ── Branding ── */
.brandMark {
  font-size: 1.8rem;
  color: #5865f2;
  margin-bottom: 0.5rem;
  display: block;
  text-align: center;
  filter: drop-shadow(0 0 12px rgba(88, 101, 242, 0.4));
}

.title {
  font-weight: 800;
  font-size: 1.5rem;
  color: #fff;
  margin-bottom: 0.3rem;
  text-align: center;
  letter-spacing: -0.02em;
}

.subtitle {
  color: rgba(255, 255, 255, 0.55);
  font-size: 0.88rem;
  margin-bottom: 1.6rem;
  text-align: center;
  font-weight: 400;
}

/* ── Form ── */
.form {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.label {
  font-size: 0.7rem;
  font-weight: 700;
  color: rgba(255, 255, 255, 0.6);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

.input {
  background: rgba(0, 0, 0, 0.25);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 8px;
  padding: 0.75rem 1rem;
  color: #fff;
  font-size: 0.92rem;
  font-family: inherit;
  font-weight: 400;
  transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
  outline: none;
  width: 100%;
  box-sizing: border-box;
}

.input:focus {
  border-color: #5865f2;
  box-shadow: 0 0 0 3px rgba(88, 101, 242, 0.25);
  background: rgba(0, 0, 0, 0.35);
}

.input::placeholder {
  color: rgba(255, 255, 255, 0.25);
}

/* ── Error message ── */
.errorBox {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.7rem 1rem;
  background: rgba(237, 66, 69, 0.12);
  border: 1px solid rgba(237, 66, 69, 0.3);
  border-radius: 8px;
  color: #f38688;
  font-size: 0.82rem;
  font-weight: 500;
  animation: shakeIn 0.4s ease;
}

.errorIcon {
  font-size: 1rem;
  flex-shrink: 0;
}

@keyframes shakeIn {

  0%,
  100% {
    transform: translateX(0);
  }

  20% {
    transform: translateX(-6px);
  }

  40% {
    transform: translateX(6px);
  }

  60% {
    transform: translateX(-4px);
  }

  80% {
    transform: translateX(4px);
  }
}

/* ── Submit button ── */
.submitBtn {
  margin-top: 0.5rem;
  padding: 0.8rem;
  background: #5865f2;
  color: #fff;
  border: none;
  border-radius: 8px;
  font-size: 0.95rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.2s, transform 0.15s, box-shadow 0.2s;
  width: 100%;
  position: relative;
  box-shadow: 0 4px 15px rgba(88, 101, 242, 0.3);
}

.submitBtn:hover:not(:disabled) {
  background: #4752c4;
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(88, 101, 242, 0.4);
}

.submitBtn:active:not(:disabled) {
  transform: translateY(0);
}

.submitBtn:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

/* loading spinner */
.spinner {
  display: inline-block;
  width: 16px;
  height: 16px;
  border: 2px solid rgba(255, 255, 255, 0.3);
  border-top-color: #fff;
  border-radius: 50%;
  animation: spin 0.6s linear infinite;
  vertical-align: middle;
  margin-right: 0.4rem;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* ── Divider ── */
.divider {
  height: 1px;
  background: rgba(255, 255, 255, 0.06);
  margin: 1.5rem 0;
}

/* ── Footer link ── */
.footer {
  text-align: center;
  font-size: 0.84rem;
  color: rgba(255, 255, 255, 0.4);
}

.footerLink {
  color: #00a8fc;
  font-weight: 500;
  text-decoration: none;
  transition: color 0.15s;
}

.footerLink:hover {
  text-decoration: underline;
  color: #00c8ff;
}

/* ── Responsive ── */
@media (max-width: 520px) {
  .card {
    padding: 2rem 1.5rem 1.5rem;
    border-radius: 12px;
  }

  .title {
    font-size: 1.3rem;
  }
}

/* ── OAuth Section ── */
.oauthSection {
  margin-top: 1.2rem;
}

.oauthDivider {
  display: flex;
  align-items: center;
  gap: 0.8rem;
  margin-bottom: 1.2rem;
}

.oauthDivider::before,
.oauthDivider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: rgba(255, 255, 255, 0.08);
}

.oauthDivider span {
  color: rgba(255, 255, 255, 0.35);
  font-size: 0.78rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

.googleBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.7rem;
  width: 100%;
  padding: 0.75rem 1rem;
  background: #ffffff;
  color: #3c4043;
  border: none;
  border-radius: 8px;
  font-size: 0.92rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.2s, transform 0.15s, box-shadow 0.2s;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.googleBtn:hover {
  background: #f1f3f4;
  transform: translateY(-2px);
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.2);
}

.googleBtn:active {
  transform: translateY(0);
  background: #e8eaed;
}

.googleIcon {
  flex-shrink: 0;
}

/* ═══════════════════════════════════════════════════════════════════════════
   LinkSphere — Create/Join Server Modal (Modern Minimalist)
   ═══════════════════════════════════════════════════════════════════════════ */

.overlay {
    position: fixed;
    inset: 0;
    background-color: rgba(0, 0, 0, 0.6);
    backdrop-filter: blur(4px);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 1000;
}

.modal {
    background-color: #141820;
    width: 440px;
    max-width: 90%;
    border-radius: 16px;
    padding: 0;
    box-shadow: 0 16px 48px rgba(0, 0, 0, 0.5);
    border: 1px solid rgba(255, 255, 255, 0.06);
    position: relative;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    font-family: 'Inter', system-ui, sans-serif;
}

.mainView,
.tellUsMoreView {
    padding: 24px;
}

.customizeView,
.joinView {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.closeButton,
.closeBtn {
    position: absolute;
    top: 16px;
    right: 16px;
    background: none;
    border: none;
    cursor: pointer;
    color: #555a6e;
    padding: 4px;
    transition: color 0.15s;
    z-index: 10;
}

.closeButton:hover,
.closeBtn:hover {
    color: #e4e6eb;
}

.closeButton svg {
    width: 24px;
    height: 24px;
}

.header {
    text-align: center;
    margin-bottom: 24px;
    padding-top: 16px;
}

.customizeView .header,
.joinView .header {
    padding-left: 24px;
    padding-right: 24px;
}

.title {
    color: #e4e6eb;
    font-size: 22px;
    font-weight: 700;
    margin: 0 0 8px 0;
}

.subtitle {
    color: #8b8fa3;
    font-size: 14px;
    margin: 0;
    line-height: 1.4;
}

.description {
    color: #8b8fa3;
    font-size: 14px;
    margin: 0;
    line-height: 1.4;
}

.content {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

/* Option Blocks */
.optionBlock,
.tellUsOptionBlock {
    background-color: #0d1017;
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 10px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    cursor: pointer;
    width: 100%;
    transition: all 0.15s;
    font-family: inherit;
}

.tellUsOptionBlock {
    padding: 16px;
    margin-top: 8px;
}

.optionBlock:hover,
.tellUsOptionBlock:hover {
    background-color: #1f2538;
    border-color: rgba(255, 255, 255, 0.1);
}

.optionBlockMain {
    display: flex;
    align-items: center;
    gap: 12px;
}

.optionIcon {
    width: 24px;
    height: 24px;
    color: #e4e6eb;
}

.optionEmoji {
    font-size: 20px;
}

.couchCtn,
.earthCtn {
    width: 24px;
    height: 24px;
    color: #e4e6eb;
    flex-shrink: 0;
}

.optionLabel {
    color: #e4e6eb;
    font-size: 14px;
    font-weight: 600;
}

.arrowIcon {
    width: 20px;
    height: 20px;
    color: #555a6e;
}

.sectionHeading {
    color: #555a6e;
    font-size: 10px;
    font-weight: 700;
    margin: 16px 0 0 0;
    text-transform: uppercase;
    letter-spacing: 0.08em;
}

/* Join section */
.joinSection {
    background-color: #0d1017;
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 10px;
    padding: 16px;
    text-align: center;
    margin-top: 16px;
}

.joinHeading {
    color: #e4e6eb;
    font-size: 15px;
    font-weight: 600;
    margin: 0 0 10px 0;
}

.joinMenuButton {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    border: none;
    border-radius: 8px;
    color: #fff;
    padding: 10px 20px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    width: 100%;
    font-family: inherit;
    transition: all 0.2s;
}

.joinMenuButton:hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

/* Tell us more */
.skipDesc {
    text-align: center;
    margin-top: 24px;
    margin-bottom: 0;
    color: #8b8fa3;
    font-size: 13px;
}

.skipLink {
    color: #7c3aed;
    font-weight: 600;
    cursor: pointer;
}

.skipLink:hover {
    text-decoration: underline;
}

/* Inputs */
.inputGroup {
    width: 100%;
    margin-bottom: 16px;
}

.inputLabel {
    display: block;
    color: #8b8fa3;
    font-size: 10px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.06em;
    margin-bottom: 8px;
}

.nameInput,
.inputField {
    width: 100%;
    background-color: #0d1017;
    border: 1px solid rgba(255, 255, 255, 0.06);
    color: #e4e6eb;
    border-radius: 10px;
    padding: 12px 14px;
    font-size: 14px;
    outline: none;
    box-sizing: border-box;
    font-family: inherit;
    transition: border-color 0.2s, box-shadow 0.2s;
}

.nameInput:focus,
.inputField:focus {
    border-color: #7c3aed;
    box-shadow: 0 0 0 3px rgba(124, 58, 237, 0.15);
}

.asterisk {
    color: #ef4444;
}

/* Customize */
.contentCustomize {
    padding: 0 24px 24px 24px;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.avatarUpload {
    width: 80px;
    height: 80px;
    border-radius: 18px;
    border: 2px dashed #555a6e;
    background: transparent;
    color: #e4e6eb;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
    transition: border-color 0.15s;
    overflow: hidden;
    margin-bottom: 24px;
}

.avatarUpload:hover {
    border-color: #7c3aed;
}

.avatarPreview {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.uploadInner {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
}

.uploadInner svg {
    width: 32px;
    height: 32px;
    color: #8b8fa3;
}

.uploadInner span {
    font-size: 10px;
    font-weight: 700;
    color: #8b8fa3;
}

.hiddenInput {
    display: none;
}

.legalNote {
    font-size: 11px;
    color: #555a6e;
    line-height: 1.4;
    margin: 0;
    width: 100%;
}

.blueLink {
    color: #7c3aed;
    cursor: pointer;
}

.blueLink:hover {
    text-decoration: underline;
}

/* Join view */
.joinContentWrapper {
    padding: 0 24px 24px 24px;
}

.examplesSection {
    margin-bottom: 24px;
}

.examplesTitle {
    color: #8b8fa3;
    font-size: 11px;
    font-weight: 500;
    margin: 0 0 8px 0;
}

.tagsContainer {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}

.tag {
    background-color: #0d1017;
    color: #8b8fa3;
    padding: 5px 10px;
    border-radius: 8px;
    font-size: 12px;
    border: 1px solid rgba(255, 255, 255, 0.06);
}

.discoverBlock {
    background-color: #0d1017;
    border-radius: 10px;
    padding: 12px 16px;
    display: flex;
    align-items: center;
    gap: 12px;
    cursor: pointer;
    border: 1px solid rgba(255, 255, 255, 0.06);
    transition: all 0.15s;
}

.discoverBlock:hover {
    background-color: #1f2538;
    border-color: rgba(255, 255, 255, 0.1);
}

.discoverIconWrapper {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    border-radius: 10px;
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
}

.discoverTextContainer {
    flex: 1;
}

.discoverTitle {
    color: #e4e6eb;
    font-weight: 600;
    font-size: 14px;
    margin-bottom: 2px;
}

.discoverSubtitle {
    color: #8b8fa3;
    font-size: 12px;
    line-height: 1.3;
}

/* Footers */
.footerOnlyBack {
    padding-top: 24px;
    display: flex;
    justify-content: flex-start;
}

.footerWithFlex {
    padding: 16px 24px;
    background-color: #0d1017;
    border-top: 1px solid rgba(255, 255, 255, 0.06);
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: auto;
}

.backButton {
    background: transparent;
    border: none;
    color: #8b8fa3;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    padding: 0;
    font-family: inherit;
    transition: color 0.15s;
}

.backButton:hover {
    color: #e4e6eb;
}

.actionBtn,
.createBtn {
    background: linear-gradient(135deg, #7c3aed, #3b82f6);
    color: white;
    border: none;
    padding: 10px 24px;
    border-radius: 10px;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: all 0.2s;
}

.actionBtn:hover,
.createBtn:hover {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(124, 58, 237, 0.4);
}

.actionActive {
    cursor: pointer;
    opacity: 1;
}

.actionDisabled {
    cursor: not-allowed;
    opacity: 0.4;
}

.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 2rem;
  height: 56px;
  background: rgba(26, 17, 71, 0.6);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
