                    )}

                    {/* ── Pending Tab ── */}
                    {activeHomeTab === 'pending' && (
                      <div className={styles.friendListSection}>
                        <div className={styles.friendListHeader}>Pending — {friendsData.incoming.length + friendsData.outgoing.length}</div>
