import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import AuthForm from "../components/AuthForm";

const LOGIN_FIELDS = [
  { name: "email", label: "Email", type: "email", placeholder: "you@example.com" },
  { name: "password", label: "Password", type: "password", placeholder: "Your password" },
];

export default function Login() {
  const navigate = useNavigate();
  const auth = useAuth();
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (data) => {
    setError("");
    setLoading(true);

    try {
      const res = await fetch("/api/users/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });

      const json = await res.json();

      if (res.ok) {
        auth.login({ token: json.token, user: json.user });
        navigate("/app");
      } else {
        setError(json.error || "Login failed. Check your credentials.");
      }
    } catch (err) {
      console.error("Login error:", err);
      setError("Could not connect to server. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthForm
      title="Welcome back"
      subtitle="Log in to your LinkSphere account"
      fields={LOGIN_FIELDS}
      submitLabel="Log In"
      onSubmit={handleLogin}
      footerText="Don't have an account?"
      footerLink="/signup"
      footerLinkText="Sign up"
      error={error}
      loading={loading}
    />
  );
}

import { useEffect, useState, useRef } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function OAuthCallback() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { login } = useAuth();
  const [error, setError] = useState("");
  const hasRun = useRef(false);

  useEffect(() => {
    if (hasRun.current) return;
    hasRun.current = true;

    const token = searchParams.get("token");
    const userParam = searchParams.get("user");

    if (!token || !userParam) {
      setError("Authentication failed. Missing credentials.");
      setTimeout(() => navigate("/login", { replace: true }), 2000);
      return;
    }

    try {
      const user = JSON.parse(decodeURIComponent(userParam));
      login({ token, user });
      navigate("/app", { replace: true });
    } catch (err) {
      console.error("OAuth callback error:", err);
      setError("Authentication failed. Please try again.");
      setTimeout(() => navigate("/login", { replace: true }), 2000);
    }
  }, [searchParams, navigate, login]);

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      justifyContent: "center",
      background: "#313338",
      color: "#f2f3f5",
      fontFamily: "'Outfit', 'Noto Sans', sans-serif",
      gap: "1rem",
    }}>
      {error ? (
        <p style={{ color: "#f38688" }}>{error}</p>
      ) : (
        <>
          <div style={{
            width: "32px",
            height: "32px",
            border: "3px solid rgba(88, 101, 242, 0.3)",
            borderTopColor: "#5865f2",
            borderRadius: "50%",
            animation: "spin 0.6s linear infinite",
          }} />
          <p style={{ fontSize: "1.1rem", opacity: 0.8 }}>Signing you in...</p>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </>
      )}
    </div>
  );
}

import { useState } from "react";
import { useNavigate } from "react-router-dom";
import AuthForm from "../components/AuthForm";

const SIGNUP_FIELDS = [
  { name: "username", label: "Username", type: "text", placeholder: "Choose a username" },
  { name: "email", label: "Email", type: "email", placeholder: "you@example.com" },
  { name: "dob", label: "Date of Birth", type: "date", placeholder: "" },
  { name: "password", label: "Password", type: "password", placeholder: "Create a password" },
  { name: "confirmPassword", label: "Confirm Password", type: "password", placeholder: "Confirm your password" }
];

export default function Signup() {
  const navigate = useNavigate();
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSignup = async (data) => {
    setError("");

    if (data.password !== data.confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    setLoading(true);

    try {
      const { confirmPassword, ...payload } = data;

      const res = await fetch("/api/users/signup", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const json = await res.json();

      if (res.ok) {
        navigate("/login");
      } else {
        setError(json.error || "Signup failed. Please try again.");
      }
    } catch (err) {
      console.error("Signup error:", err);
      setError("Could not connect to server. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthForm
      title="Create account"
      subtitle="Join LinkSphere and start connecting"
      fields={SIGNUP_FIELDS}
      submitLabel={loading ? "Creating Account..." : "Create Account"}
      onSubmit={handleSignup}
      footerText="Already have an account?"
      footerLink="/login"
      footerLinkText="Log in"
      error={error}
      loading={loading}
    />
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
