            if (fileToUpload) {
                const formData = new FormData();
                formData.append("image", fileToUpload);
                const uploadRes = await fetch(`${API}/upload`, {
                    method: "POST",
                    headers: {
                        Authorization: `Bearer ${localStorage.getItem("token")}`, // optional if upload route needs it
                    },
                    body: formData,
                });
